<?php ob_start();?><section class="page-heading"><div><p class="eyebrow">Visão da coordenação</p><h1>Consolidado de alunos</h1><p>Informações dos relatórios aprovados, reunidas para apoiar o conselho.</p></div><div class="actions"><a class="button" href="?formato=csv">Exportar planilha (CSV)</a><button class="primary" type="button" onclick="window.print()">Imprimir</button></div></section><section class="card"><div class="section-heading"><div><h2>Alunos indicados</h2><p><span id="consolidated-count"><?=count($rows)?></span> registro(s) aprovado(s)</p></div><?php if($rows):?><label class="search"><span class="sr-only">Buscar no consolidado</span><span aria-hidden="true">⌕</span><input type="search" placeholder="Buscar aluno, turma ou disciplina" data-table-search="#consolidated-table"></label><?php endif;?></div><?php if(!$rows):?><div class="empty-state"><span aria-hidden="true">✓</span><h3>Ainda não há dados consolidados</h3><p>Os alunos aparecerão aqui após a aprovação dos relatórios.</p></div><?php else:?><div class="table"><table id="consolidated-table"><thead><tr><th>Aluno</th><th>Turma</th><th>Disciplina</th><th>Professor</th><th>Nota</th><th>Dificuldades</th><th>Intervenções</th></tr></thead><tbody><?php foreach($rows as$r):?><tr><td data-label="Aluno"><strong><?=e($r['aluno'])?></strong></td><td data-label="Turma"><?=e($r['turma'])?></td><td data-label="Disciplina"><?=e($r['disciplina'])?></td><td data-label="Professor"><?=e($r['professor'])?></td><td data-label="Nota"><?=e($r['nota'])?></td><td data-label="Dificuldades"><?=e($r['dificuldades'])?></td><td data-label="Intervenções"><?=e($r['intervencoes'])?></td></tr><?php endforeach;?></tbody></table></div><?php endif;?></section><?php $content=ob_get_clean();require __DIR__.'/layout.php';
